"use client";

import { useSession, signOut } from "next-auth/react";
import { useEffect } from "react";
import { useRouter } from "next/navigation";

export default function Dashboard() {
  const { data: session, status } = useSession();
  const router = useRouter();

  // 1. Protection: Kick them out if not logged in
  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
    }
  }, [status, router]);

  if (status === "loading") return <p className="p-10 text-white">Loading...</p>;

  return (
    <div className="min-h-screen bg-gray-900 text-white p-10">
      {/* Header */}
      <div className="flex justify-between items-center mb-10">
        <h1 className="text-3xl font-bold text-blue-400">GitHelix Dashboard</h1>
        <div className="flex items-center gap-4">
          <img 
            src={session?.user?.image || ""} 
            className="w-10 h-10 rounded-full border border-gray-500"
          />
          <button 
            onClick={() => signOut({ callbackUrl: "/login" })}
            className="text-sm text-red-400 hover:text-red-300"
          >
            Sign Out
          </button>
        </div>
      </div>

      {/* The Main Action Area */}
      <div className="bg-gray-800 p-6 rounded-xl border border-gray-700">
        <h2 className="text-xl font-semibold mb-4">Connection Status</h2>
        
        {/* Debugging: Show that we actually have the Golden Ticket */}
        <div className="bg-black p-4 rounded font-mono text-sm text-green-400 overflow-hidden text-ellipsis whitespace-nowrap">
          Access Token: {(session as any)?.accessToken ? "✅ SECURED" : "❌ MISSING"}
        </div>

        <button className="mt-6 px-6 py-3 bg-blue-600 hover:bg-blue-500 rounded-lg font-bold w-full">
          Scan Repository (Coming Soon)
        </button>
      </div>
    </div>
  );
}